def hensel_cubic(pser, qser):
    """Roots of v^3 + pser v + qser with SIMPLE leading roots (level 1)."""
    roots = []
    vp = pser.valuation() if pser != _sage_const_0  else _sage_const_10 **_sage_const_6 
