        poly = Pz(_sage_const_0 )
        if _sage_const_3 *k == m:
            poly += cc**_sage_const_3 
        if pser != _sage_const_0  and vp + k == m:
            poly += pser.coefficients()[_sage_const_0 ]*cc
        if qser != _sage_const_0  and vq == m:
            poly += qser.coefficients()[_sage_const_0 ]
